 ```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  body {
    font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    max-width: 800px;
    margin: 0 auto;
    padding: 20px;
    line-height: 1.4;
  }
  h1, h2 { margin-top: 0; }
  section, form {
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 15px;
    margin-bottom: 15px;
  }
  label {
    display: inline-block;
    margin-right: 12px;
    margin-bottom: 8px;
  }
  input, select {
    padding: 6px;
    margin-left: 4px;
  }
  button {
    padding: 6px 12px;
    cursor: pointer;
  }
  #form-error {
    color: #c00;
    min-height: 1.2em;
    margin-top: 6px;
  }
  table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10px;
  }
  th, td {
    border: 1px solid #ddd;
    padding: 8px;
    text-align: left;
  }
  th { background: #f5f5f5; }
  .exp-del { background: #fee; border: 1px solid #caa; }
  .summary {
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
    align-items: center;
  }
  .cat-total {
    background: #eef;
    padding: 6px 10px;
    border-radius: 4px;
  }
  #total { font-weight: bold; }
</style>
</head>
<body>

<h1>Personal Expense Tracker</h1>

<form id="expense-form">
  <label>Amount
    <input type="number" id="amount" step="0.01" placeholder="0.00">
  </label>
  <label>Category
    <select id="category">
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </label>
  <label>Date
    <input type="date" id="date">
  </label>
  <label>Note
    <input type="text" id="note" placeholder="Optional">
  </label>
  <button type="submit" id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</form>

<section>
  <h2>Filters</h2>
  <label>Category
    <select id="filter-category">
      <option value="all">All</option>
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </label>
  <label>From
    <input type="date" id="filter-from">
  </label>
  <label>To
    <input type="date" id="filter-to">
  </label>
</section>

<section>
  <h2>Summary</h2>
  <div class="summary">
    <div>Total: <span id="total">0.00</span></div>
    <div class="cat-total" data-cat="groceries">Groceries: 0.00</div>
    <div class="cat-total" data-cat="transport">Transport: 0.00</div>
    <div class="cat-total" data-cat="bills">Bills: 0.00</div>
    <div class="cat-total" data-cat="fun">Fun: 0.00</div>
  </div>
</section>

<section>
  <h2>Expenses</h2>
  <table>
    <thead>
      <tr>
        <th>Amount</th>
        <th>Category</th>
        <th>Date</th>
        <th>Note</th>
        <th></th>
      </tr>
    </thead>
    <tbody id="expense-list"></tbody>
  </table>
</section>

<script>
const STORAGE_KEY = 'expenses';
const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];
let expenses = [];

function loadData() {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      expenses = JSON.parse(stored);
      if (!Array.isArray(expenses)) expenses = [];
    }
  } catch (e) {
    expenses = [];
  }
  // Normalize legacy entries
  expenses.forEach(exp => {
    exp.amount = parseFloat(exp.amount) || 0;
    if (!exp.createdAt) exp.createdAt = Date.parse(exp.date) || 0;
  });
}

function saveData() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
}

function getFilters() {
  return {
    category: document.getElementById('filter-category').value,
    from: document.getElementById('filter-from').value,
    to: document.getElementById('filter-to').value
  };
}

function matchesFilters(exp, filters) {
  if (filters.category !== 'all' && exp.category !== filters.category) return false;
  if (filters.from && exp.date < filters.from) return false;
  if (filters.to && exp.date > filters.to) return false;
  return true;
}

function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

function capitalize(s) {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

function render() {
  const filters = getFilters();
  const listEl = document.getElementById('expense-list');
  listEl.innerHTML = '';

  const sorted = expenses.slice().sort((a, b) => b.createdAt - a.createdAt);

  const catTotals = {};
  CATEGORIES.forEach(c => catTotals[c] = 0);
  let total = 0;

  sorted.forEach(exp => {
    if (!matchesFilters(exp, filters)) return;

    total += exp.amount;
    catTotals[exp.category] = (catTotals[exp.category] || 0) + exp.amount;

    const row = document.createElement('tr');
    row.className = 'expense';
    row.innerHTML = `
      <td>${exp.amount.toFixed(2)}</td>
      <td>${exp.category}</td>
      <td>${exp.date}</td>
      <td>${escapeHtml(exp.note || '')}</td>
      <td><button class="exp-del" data-id="${exp.id}">Delete</button></td>
    `;
    listEl.appendChild(row);
  });

  document.getElementById('total').textContent = total.toFixed(2);
  CATEGORIES.forEach(c => {
    const el = document.querySelector(`.cat-total[data-cat="${c}"]`);
    if (el) el.textContent = `${capitalize(c)}: ${(catTotals[c] || 0).toFixed(2)}`;
  });

  listEl.querySelectorAll('.exp-del').forEach(btn => {
    btn.addEventListener('click', () => {
      expenses = expenses.filter(e => e.id !== btn.dataset.id);
      saveData();
      render();
    });
  });
}

document.getElementById('expense-form').addEventListener('submit', function (e) {
  e.preventDefault();

  const amountEl = document.getElementById('amount');
  const dateEl = document.getElementById('date');
  const noteEl = document.getElementById('note');
  const categoryEl = document.getElementById('category');
  const errorEl = document.getElementById('form-error');

  const amount = parseFloat(amountEl.value);
  const date = dateEl.value.trim();

  if (isNaN(amount) || amount <= 0) {
    errorEl.textContent = 'Please enter a positive numeric amount greater than zero.';
    return;
  }
  if (!date) {
    errorEl.textContent = 'Please select a date.';
    return;
  }

  errorEl.textContent = '';

  expenses.push({
    id: Date.now().toString() + Math.random().toString(36).slice(2),
    amount: amount,
    category: categoryEl.value,
    date: date,
    note: noteEl.value.trim(),
    createdAt: Date.now()
  });

  saveData();
  amountEl.value = '';
  noteEl.value = '';
  render();
});

document.getElementById('filter-category').addEventListener('change', render);
document.getElementById('filter-from').addEventListener('input', render);
document.getElementById('filter-to').addEventListener('input', render);

loadData();
render();
</script>

</body>
</html>
